#!/usr/bin/env node
/**
 * Generates an extra-large realistic project fixture for typeship performance testing.
 * Produces 6 slices × ~150 types = ~900+ published types across ~70+ source files.
 * Scale: "hundreds of types per slice" as found in real enterprise backends.
 */

import { mkdirSync, writeFileSync, rmSync, existsSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, 'extra-large-project');

// Only clean the generated src/ tree so the root directory (and any open shell
// sessions pointing to it) is never invalidated by deletion + recreation.
const SRC_ROOT = join(ROOT, 'src');
if (existsSync(SRC_ROOT)) rmSync(SRC_ROOT, { recursive: true });

// ─── helpers ────────────────────────────────────────────────────────────────

function write(relPath, content) {
  const abs = join(ROOT, relPath);
  mkdirSync(dirname(abs), { recursive: true });
  writeFileSync(abs, content, 'utf8');
}

const header = `// This file is part of the extra-large-project performance fixture.\n// Generated by gen-extra-large-project.mjs — do not edit manually.\n\n`;

function pub(text) { return `/** @publish */\n${text}`; }

function enumType(name, values) {
  const members = values.map(([k, v]) => `  ${k} = '${v}',`).join('\n');
  return pub(`export enum ${name} {\n${members}\n}\n`);
}

function iface(name, fields, generics = '') {
  const members = fields.map(([n, t]) => `  ${n}: ${t};`).join('\n');
  return pub(`export interface ${name}${generics} {\n${members}\n}\n`);
}

function typeAlias(name, rhs) {
  return pub(`export type ${name} = ${rhs};\n`);
}

// ─── shared ─────────────────────────────────────────────────────────────────

write('src/shared/pagination.ts', header + [
  typeAlias('SortOrder', `'asc' | 'desc'`),
  typeAlias('CursorToken', 'string'),
  iface('PageInfo', [['page','number'],['pageSize','number'],['total','number'],['totalPages','number'],['hasNext','boolean'],['hasPrev','boolean']]),
  iface('CursorPageInfo', [['cursor','CursorToken | null'],['hasNext','boolean'],['count','number'],['totalEstimate','number | null']]),
  iface('SortField', [['field','string'],['order','SortOrder'],['nullsFirst','boolean']]),
  iface('PaginationInput', [['page','number'],['pageSize','number'],['sort','SortField[]'],['cursor','CursorToken | null']]),
  iface('PaginatedResponse<T>', [['items','T[]'],['pageInfo','PageInfo'],['sort','SortField | null']], '<T>'),
  iface('CursorResponse<T>', [['edges','T[]'],['pageInfo','CursorPageInfo']], '<T>'),
  iface('FilterOp', [['field','string'],['operator','string'],['value','unknown']]),
  iface('FilterGroup', [['combinator',`'and' | 'or'`],['filters','FilterOp[]'],['groups','FilterGroup[]']]),
].join('\n'));

