// ─── summary ─────────────────────────────────────────────────────────────────

const path = await import('node:path');
const fs = await import('node:fs');

function countTypes(dir) {
  let count = 0;
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) count += countTypes(full);
    else if (entry.name.endsWith('.ts') && entry.name !== 'index.ts') {
      const src = fs.readFileSync(full, 'utf8');
      count += (src.match(/@publish/g) || []).length;
    }
  }
  return count;
}

const files = fs.readdirSync(path.join(ROOT, 'src'), { recursive: true })
  .filter(f => typeof f === 'string' && f.endsWith('.ts')).length;

const types = countTypes(path.join(ROOT, 'src'));

console.log(`✔  Generated extra-large-project fixture`);
console.log(`   Source files : ${files}`);
console.log(`   Published    : ~${types} types`);
console.log(`   Location     : ${ROOT}`);
